Here's a Node.js script that reads CSV from stdin, auto-detects delimiters, handles quoted fields, and outputs newline-delimited JSON:

```javascript
#!/usr/bin/env node

const { createReadStream } = require('fs');
const { pipeline } = require('stream');
const { Transform } = require('stream');

class CSVParser extends Transform {
  constructor(options = {}) {
    super(options);
    this.buffer = '';
    this.delimiter = null;
    this.headers = null;
    this.rowIndex = 0;
  }

  detectDelimiter(line) {
    // Count occurrences of potential delimiters
    const delimiters = [',', '\t', ';'];
    const counts = delimiters.map(d => {
      let count = 0;
      let inQuotes = false;
      let prevChar = '';

      for (const char of line) {
        if (char === '"' && prevChar !== '\\') {
          inQuotes = !inQuotes;
        } else if (char === d && !inQuotes) {
          count++;
        }
        prevChar = char;
      }

      return { delimiter: d, count };
    });

    // Return the delimiter with the highest count
    return counts.reduce((max, curr) => curr.count > max.count ? curr : max).delimiter;
  }

  parseCSVLine(line) {
    const fields = [];
    let currentField = '';
    let inQuotes = false;
    let i = 0;

    while (i < line.length) {
      const char = line[i];
      const nextChar = line[i + 1];

      if (char === '"') {
        if (inQuotes) {
          // Check if this is an escaped quote
          if (nextChar === '"') {
            currentField += '"';
            i++; // Skip the next quote
          } else {
            // End of quoted field
            inQuotes = false;
          }
        } else {
          // Start of quoted field
          inQuotes = true;
        }
      } else if (char === this.delimiter && !inQuotes) {
        // End of field
        fields.push(currentField);
        currentField = '';
      } else {
        currentField += char;
      }

      i++;
    }

    // Add the last field
    fields.push(currentField);

    return fields;
  }

  processLine(line) {
    // Skip empty lines
    if (!line.trim()) return;

    // Detect delimiter on first non-empty line
    if (!this.delimiter) {
      this.delimiter = this.detectDelimiter(line);
    }

    const fields = this.parseCSVLine(line);

    // First row contains headers
    if (!this.headers) {
      this.headers = fields;
      return;
    }

    // Create object from fields
    const obj = {};
    for (let i = 0; i < this.headers.length; i++) {
      obj[this.headers[i]] = fields[i] || '';
    }

    // Output as JSON
    this.push(JSON.stringify(obj) + '\n');
  }

  _transform(chunk, encoding, callback) {
    this.buffer += chunk.toString();

    // Process complete lines
    const lines = this.buffer.split(/\r?\n/);
    this.buffer = lines.pop() || ''; // Keep incomplete line in buffer

    for (const line of lines) {
      this.processLine(line);
    }

    callback();
  }

  _flush(callback) {
    // Process any remaining data
    if (this.buffer) {
      this.processLine(this.buffer);
    }
    callback();
  }
}

// Main execution
if (require.main === module) {
  const parser = new CSVParser();

  pipeline(
    process.stdin,
    parser,
    process.stdout,
    (err) => {
      if (err) {
        console.error('Error processing CSV:', err);
        process.exit(1);
      }
    }
  );
}
```

To use this script:

1. Save it to a file (e.g., `csv2json.js`)
2. Make it executable: `chmod +x csv2json.js`
3. Run it with CSV input:

```bash
# From a file
cat data.csv | node csv2json.js

# Or directly
echo 'name,age,city
"John Doe",30,"New York"
"Jane, Smith",25,Chicago' | node csv2json.js
```

The script handles:
- **Auto-detection** of delimiters (comma, tab, or semicolon) by analyzing the first line
- **Quoted fields** that can contain the delimiter character
- **Escaped quotes** within quoted fields (using `""`)
- **Headers** from the first row to create JSON object keys
- **Streaming** for efficient memory usage with large files
- **Cross-platform** line endings (`\r\n` or `\n`)

Example output:
```json
{"name":"John Doe","age":"30","city":"New York"}
{"name":"Jane, Smith","age":"25","city":"Chicago"}
```

The script uses only Node.js built-in modules and outputs newline-delimited JSON (NDJSON) format, where each line is a valid JSON object.
